// src/components/Dashboard.js
import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await fetch("/api/dashboard-stats");
        const data = await response.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching dashboard stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div className="loading">Loading dashboard data...</div>;

  const donutOptions = {
    cutout: "75%",
    plugins: {
      tooltip: { enabled: true },
      legend: { display: false },
    },
  };

  const renderSmallDonut = (label, value, color) => ({
    data: {
      labels: [label, ""],
      datasets: [
        {
          data: [value, 100 - value],
          backgroundColor: [color, "#e0e0e0"],
          borderWidth: 0,
        },
      ],
    },
  });

  const pieData = {
    labels: ["Free", "Occupied"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#4CAF50", "#F44336"],
        borderWidth: 0,
      },
    ],
  };

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2196F3",
        barThickness: 20,
      },
    ],
  };

  return (
    <div className="dashboard-wrapper">
      <h2 className="dashboard-title">Welcome, Rajeshwaran</h2>

      <div className="dashboard-grid">
        <div className="card">
          <h4 className="card-title">Availability</h4>
          <Doughnut data={pieData} options={donutOptions} />
          <div className="donut-center-text large">
            {stats.pieChart.free}<br /><small>Free</small><br />
            {stats.pieChart.occupied}<br /><small>Occupied</small>
          </div>
        </div>

        <div className="card">
          <h4 className="card-title">Projector Rooms</h4>
          <Doughnut data={renderSmallDonut("Projectors", stats.resources.projectorRooms, "#ff9800").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.projectorRooms}</div>
        </div>

        <div className="card">
          <h4 className="card-title">Free Labs</h4>
          <Doughnut data={renderSmallDonut("Labs", stats.resources.labs, "#9c27b0").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.labs}</div>
        </div>

        <div className="card">
          <h4 className="card-title">Free Rooms</h4>
          <Doughnut data={renderSmallDonut("Classrooms", stats.resources.classrooms, "#3f51b5").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.classrooms}</div>
        </div>

        <div className="card">
          <h4 className="card-title">Not Occupied</h4>
          <Doughnut data={renderSmallDonut("Available", stats.resources.totalRooms - stats.pieChart.occupied, "#009688").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.totalRooms - stats.pieChart.occupied}</div>
        </div>

        <div className="card full">
          <h3 className="card-heading">Free Rooms per Weekday</h3>
          <Bar
            data={barData}
            options={{
              responsive: true,
              plugins: { legend: { display: false } },
              scales: { y: { beginAtZero: true } },
            }}
          />
        </div>

        <div className="card full">
          <h3 className="card-heading">Resource Summary</h3>
          <ul className="resource-summary">
            <li><strong>Total Rooms:</strong> {stats.resources.totalRooms}</li>
            <li><strong>Labs:</strong> {stats.resources.labs} / {stats.resources.totalRooms}
            <div className="progress-bar"><div style={{ width: `${(stats.resources.labs / stats.resources.totalRooms) * 100}%` }} /></div>
          </li>

            <li><strong>Projector Rooms:</strong> {stats.resources.projectorRooms}</li>
            <li><strong>Classrooms:</strong> {stats.resources.classrooms}</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
